using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
int t,p,xx,yy,he;
short vis[10010][10010];
int dfs(int x,int y)
{
	if(vis[x][y]==-1)return 3;
	if(vis[x][y]!=0)return vis[x][y];
	vis[x][y]=-1;
	if(x==0)return vis[x][y]=1;
	if(y==0)return vis[x][y]=2;
	return vis[x][y]=dfs((x+y)%p,((x+y)%p+y)%p);
}
signed main()
{
	t=read();p=read();
	FOR(i,1,t)
	{
		xx=read();yy=read();
		he=dfs(xx,yy);
		if(he==3)puts("error");
		if(he==2)writeln(2);
		if(he==1)writeln(1);
	}
	return 0;
}
